import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import HeroCarousel from '../components/home/herocarousel';
import PromoBanner from '../components/home/promobanner';
import CategoryGrid from '../components/home/catergorygrid';
import ProductGrid from '../components/home/productgrid';
import { fetchProducts } from '../store/slices/productslice';

const HomePage = () => {
  const dispatch = useDispatch();
  const { items, featured } = useSelector((state) => state.products);

  useEffect(() => {
    dispatch(fetchProducts({ limit: 10, featured: true }));
  }, [dispatch]);

  const slides = [
    {
      id: 1,
      image:
        'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=1200&h=600&fit=crop',
      title: 'Modern Living Room Sets',
      subtitle: 'Transform your space with our premium collection',
      tag: 'Best Seller',
    },
    {
      id: 2,
      image:
        'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=1200&h=600&fit=crop',
      title: 'Cozy Bedroom Essentials',
      subtitle: 'Sleep in comfort and style',
      tag: 'New',
    },
    {
      id: 3,
      image:
        'https://images.unsplash.com/photo-1617806118233-18e1de247200?w=1200&h=600&fit=crop',
      title: 'Elegant Dining Collection',
      subtitle: 'Make every meal memorable',
      tag: 'Trending',
    },
  ];

  const categories = [
    {
      id: 1,
      name: 'Sofas',
      slug: 'sofas',
      image:
        'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=400&h=400&fit=crop',
    },
    {
      id: 2,
      name: 'Beds',
      slug: 'beds',
      image:
        'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=400&h=400&fit=crop',
    },
    {
      id: 3,
      name: 'Dining',
      slug: 'dining',
      image:
        'https://images.unsplash.com/photo-1617806118233-18e1de247200?w=400&h=400&fit=crop',
    },
    {
      id: 4,
      name: 'Wardrobes',
      slug: 'wardrobes',
      image:
        'https://images.unsplash.com/photo-1595428774223-ef52624120d2?w=400&h=400&fit=crop',
    },
    {
      id: 5,
      name: 'Study',
      slug: 'study',
      image:
        'https://images.unsplash.com/photo-1518455027359-f3f8164ba6bd?w=400&h=400&fit=crop',
    },
    {
      id: 6,
      name: 'Decor',
      slug: 'decor',
      image:
        'https://images.unsplash.com/photo-1583847661884-38e125a6158f?w=400&h=400&fit=crop',
    },
  ];

  return (
    <div className="space-y-0">
      <PromoBanner
        text="Upto 70% Off on Living Room Furniture"
        subtext="Limited time offer. Shop now!"
        bgColor="bg-red-600"
      />

      <HeroCarousel slides={slides} />

      <CategoryGrid categories={categories} />

      <ProductGrid
        title="Top Rated Products"
        subtitle="Customer favorites this month"
        products={items.slice(0, 8)}
      />

      <div className="container mx-auto px-4 py-8">
        <div className="bg-primary-800 rounded-2xl p-6 md:p-10 text-center text-white">
          <h2 className="text-2xl md:text-3xl font-bold mb-2">
            No Cost EMI Available
          </h2>
          <p className="text-primary-200 mb-6">
            Pay in easy installments starting at ₹999/month
          </p>
          <button className="bg-white text-primary-800 px-6 py-2.5 rounded-lg font-semibold hover:bg-primary-50 transition">
            Explore EMI Options
          </button>
        </div>
      </div>

      <ProductGrid
        title="New Arrivals"
        subtitle="Fresh designs for your home"
        products={items.slice(2, 6)}
      />
    </div>
  );
};

export default HomePage;
